import React from 'react';
import { Link, Outlet, useLocation } from 'react-router-dom';
import { Button } from '../ui/button';
import { cn } from '../../lib/utils';
import { Sheet, SheetContent, SheetTrigger } from '../ui/sheet';
import { Menu, Globe } from 'lucide-react';
import { useTranslation } from 'react-i18next';

const docsSidebarItemKeys = [
  { key: 'docs.sidebar.quick_start', to: '/docs' },
  { key: 'docs.sidebar.api_docs', to: '/docs/api' },
  { key: 'docs.sidebar.sdk', to: '/docs/sdk' },
  { key: 'docs.sidebar.tools', to: '/docs/tools' },
  { key: 'docs.sidebar.billing', to: '/docs/billing' },
  { key: 'docs.sidebar.errors', to: '/docs/errors' },
  { key: 'docs.sidebar.faq', to: '/docs/faq' },
];

const DocsSidebarNav = ({ className }) => {
  const location = useLocation();
  const { t } = useTranslation();

  return (
    <nav className={cn('flex flex-col gap-0', className)}>
      {docsSidebarItemKeys.map((item) => {
        const isActive = location.pathname === item.to;
        return (
          <Link
            key={item.to}
            to={item.to}
            className={cn(
              'relative px-4 py-2.5 text-sm font-light transition-colors border-l-2 no-underline',
              isActive
                ? 'border-l-xyz-blue-6 text-white bg-white/[0.03]'
                : 'border-l-transparent text-xyz-white-5 hover:text-white hover:bg-white/[0.03]'
            )}
          >
            {t(item.key)}
          </Link>
        );
      })}
    </nav>
  );
};

const DocsLayout = () => {
  const { t, i18n } = useTranslation();
  const toggleLanguage = () => {
    i18n.changeLanguage(i18n.language === 'zh' ? 'en' : 'zh');
  };

  return (
    <div className='flex min-h-screen flex-col bg-xyz-gray-10'>
      {/* Header */}
      <header className='sticky top-0 z-50 w-full border-b border-xyz-white-1 bg-xyz-gray-10/95 backdrop-blur supports-[backdrop-filter]:bg-xyz-gray-10/80'>
        <div className='container mx-auto flex h-14 max-w-screen-xl items-center px-4'>
          <Link to='/' className='mr-6 flex items-center gap-2 no-underline'>
            <img src={process.env.PUBLIC_URL + '/logo.svg'} alt='logo' className='h-6 w-6' />
            <span className='text-lg font-medium text-white' style={{ fontFamily: "'JetBrains Mono', monospace" }}>
              Alaya Code
            </span>
          </Link>
          <nav className='hidden md:flex items-center space-x-6 text-sm font-light'>
            <Link
              to='/docs'
              className='transition-colors text-xyz-blue-5 no-underline'
            >
              {t('nav.docs')}
            </Link>
          </nav>
          <div className='ml-auto flex items-center space-x-2'>
            <Button
              variant='ghost'
              size='sm'
              onClick={toggleLanguage}
              className='gap-1 text-xyz-white-5 hover:text-white hover:bg-white/[0.05]'
            >
              <Globe className='h-4 w-4' />
              <span className='text-xs'>{i18n.language === 'zh' ? 'EN' : '中文'}</span>
            </Button>
            <Button
              variant='ghost'
              size='sm'
              asChild
              className='text-xyz-white-5 hover:text-white hover:bg-white/[0.05]'
            >
              <Link to='/login'>{t('nav.login')}</Link>
            </Button>
          </div>
          <Sheet>
            <SheetTrigger asChild>
              <Button variant='outline' size='icon' className='shrink-0 md:hidden ml-2 border-xyz-white-2 text-white hover:bg-white/[0.05]'>
                <Menu className='h-5 w-5' />
              </Button>
            </SheetTrigger>
            <SheetContent side='left' className='bg-xyz-gray-10 border-r-xyz-white-1'>
              <div className='mt-6'>
                <DocsSidebarNav />
              </div>
            </SheetContent>
          </Sheet>
        </div>
      </header>
      {/* Content */}
      <div className='container mx-auto flex max-w-screen-xl flex-1 px-4'>
        {/* Desktop sidebar */}
        <aside className='hidden md:block md:w-56 md:shrink-0 md:border-r md:border-xyz-white-1 md:pr-0 md:pt-6'>
          <DocsSidebarNav />
        </aside>
        {/* Main content */}
        <main className='flex-1 py-6 md:pl-8'>
          <div className='max-w-none'>
            <Outlet />
          </div>
        </main>
      </div>
    </div>
  );
};

export default DocsLayout;
